<?php namespace App\Repositories\Timetable;use App\Repositories\BaseRepository;use App\Models\Timetable\RoomAllocation;use Illuminate\Database\Eloquent\Collection;class RoomAllocationRepository extends BaseRepository{    public function __construct(RoomAllocation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByRoom(string $room): Collection    {        return $this->findByField('room', $room);    }    public function findByDay(string $day): Collection    {        return $this->findByField('day', $day);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('date', [$startDate, $endDate])->get();    }    public function checkRoomAvailability(string $room, string $day, string $startTime, string $endTime): bool    {        return $this->query()->where('room', $room)->where('day', $day)->where(function ($q) use ($startTime, $endTime) {                $q->whereBetween('start_time', [$startTime, $endTime])->orWhereBetween('end_time', [$startTime, $endTime]);            })->exists();    }    public function getRoomSchedule(string $room, string $day): Collection    {        return $this->query()->where('room', $room)->where('day', $day)->orderBy('start_time', 'asc')->get();    }    public function allocateRoom(array $data): RoomAllocation    {        return $this->create($data);    }    public function releaseRoom(int $id): bool    {        return $this->delete($id);    }    public function getAvailableRooms(string $day, string $startTime, string $endTime): Collection    {        $allocatedRooms = $this->query()->where('day', $day)->where(function ($q) use ($startTime, $endTime) {                $q->whereBetween('start_time', [$startTime, $endTime])->orWhereBetween('end_time', [$startTime, $endTime]);            })->pluck('room');        return $allocatedRooms;    }}